import{_ as e,a as i,b as o}from"./chunks/支持留言.NiGCLVdp.js";import{_ as t,o as s,c as n,a2 as l}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Blog","description":"","frontmatter":{},"headers":[],"relativePath":"pl-PL/Other/blog.md","filePath":"pl-PL/Other/blog.md","lastUpdated":1781962217000}'),p={name:"pl-PL/Other/blog.md"};function r(d,a,c,g,u,b){return s(),n("div",null,[...a[0]||(a[0]=[l('<h1 id="blog" tabindex="-1">Blog <a class="header-anchor" href="#blog" aria-label="Permalink to &quot;Blog&quot;">​</a></h1><p>Funkcja Blog dodaje do strony ImgBed osobną stronę bloga.</p><p>Po włączeniu odwiedzający mogą otworzyć:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/blog/</span></span></code></pre></div><p><img src="'+e+'" alt="Strona główna bloga" loading="lazy"></p><p>Blog został zaadaptowany z projektu open source <a href="https://github.com/LyraVoid/Mizuki" target="_blank" rel="noreferrer">LyraVoid/Mizuki</a>. ImgBed przepisał i zintegrował go z Vue, aby mógł działać jako część strony hostingu obrazów.</p><h2 id="gdzie-skonfigurowac" tabindex="-1">Gdzie skonfigurować <a class="header-anchor" href="#gdzie-skonfigurowac" aria-label="Permalink to &quot;Gdzie skonfigurować&quot;">​</a></h2><p>Ustawienia bloga znajdują się w:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Blog</span></span></code></pre></div><p><img src="'+i+'" alt="Ustawienia bloga" loading="lazy"></p><h2 id="pierwsza-konfiguracja" tabindex="-1">Pierwsza konfiguracja <a class="header-anchor" href="#pierwsza-konfiguracja" aria-label="Permalink to &quot;Pierwsza konfiguracja&quot;">​</a></h2><ol><li>Włącz <code>Enable</code>.</li><li>Wybierz konto GitHub, na którym ma być przechowywana konfiguracja bloga.</li><li>Kliknij <code>Update Blog</code>.</li><li>Poczekaj na komunikat powodzenia.</li><li>Otwórz <code>https://your-domain.com/blog/</code>, aby zobaczyć blog.</li></ol><p>Przy pierwszym użyciu ImgBed przygotowuje prywatne repozytorium GitHub na wybranym koncie:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Repozytorium przechowuje ustawienia bloga i treść artykułów.</p><h2 id="pisanie-wpisow" tabindex="-1">Pisanie wpisów <a class="header-anchor" href="#pisanie-wpisow" aria-label="Permalink to &quot;Pisanie wpisów&quot;">​</a></h2><p>Wpisy blogowe edytuje się w prywatnym repozytorium GitHub:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Typowy przebieg:</p><ol><li>Otwórz GitHub.</li><li>Wejdź do prywatnego repozytorium <code>imgbed-blog-config</code>.</li><li>Edytuj lub dodaj pliki wpisów.</li><li>Zacommituj zmiany.</li><li>Wróć do panelu administracyjnego ImgBed i kliknij <code>Update Blog</code>, albo kliknij logo w lewym górnym rogu strony głównej bloga trzy razy, aby uruchomić aktualizację.</li></ol><p><code>Update Blog</code> nie nadpisuje treści, które napisałeś. Ta akcja służy głównie do inicjalizacji repozytorium i odświeżenia cache bloga.</p><h2 id="obsługiwane-funkcje" tabindex="-1">Obsługiwane funkcje <a class="header-anchor" href="#obsługiwane-funkcje" aria-label="Permalink to &quot;Obsługiwane funkcje&quot;">​</a></h2><p>Blog obsługuje typowe funkcje: listę wpisów, kategorie, tagi, archiwum, wyszukiwanie, tryb ciemny i zmianę języka.</p><p>Obsługuje też komentarze i statystyki odwiedzin.</p><p><img src="'+o+'" alt="Komentarze bloga" loading="lazy"></p><p>Komentarze pojawiają się pod wpisami. Odwiedzający mogą podać avatar, pseudonim, e-mail i treść komentarza.</p><p>Statystyki pokazują wyświetlenia wpisów i odwiedziny strony, co pomaga zrozumieć ruch na blogu.</p><h2 id="url" tabindex="-1">URL <a class="header-anchor" href="#url" aria-label="Permalink to &quot;URL&quot;">​</a></h2><p>Blog zawsze działa pod <code>/blog/</code>.</p><p>Jeśli domena ImgBed wygląda tak:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com</span></span></code></pre></div><p>adres bloga to:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com/blog/</span></span></code></pre></div><p>Po wyłączeniu bloga odwiedzający nie mogą już otworzyć strony bloga.</p>',34)])])}const w=t(p,[["render",r]]);export{y as __pageData,w as default};
